end

function DbUtil:savePlayerData(player, immediate)
    if player == nil then
        return
    end
    SavePlayerGameData(player, immediate)
    SavePlayerRewardData(player, immediate)
    SavePlayerDressData(player, immediate)
    SavePlayerRuneData(player, immediate)
    SavePlayerGuideData(player, immediate)
    SavePlayerActivityData(player, immediate)
    SavePlayerDailySignInData(player, immediate)
    SavePlayerVideoAdData(player, immediate)
    SavePlayerFreeCubeLimit(player, immediate)
    SavePlayerTaskData(player, immediate)
    SavePlayerLicenseData(player, immediate)
    SavePlayerCustomShopData(player, immediate)
    SavePlayerTreasureChallengeData(player, immediate)
    SavePlayerBlockShopData(player, immediate)
    SavePlayerFreeGiftData(player, immediate)
    SavePlayerFreeTicketData(player, immediate)
end

function DbUtil:IsGetAllDataFinished(player)
    for _, key in pairs(AllKey) do
        if not DBManager:isLoadDataFinished(player.userId, key) then
            return false
        end
    end
    return true
end

return DbUtil